cmd=r'''python - <<'PY'
import json,re
from pathlib import Path
p=Path(r'E:/ax/PRJs/gpt56-scaling/runs/test1a/sol_m/receipts.json')
data=json.loads(p.read_text(encoding='utf-8'))
required=['receipt_id','store_name','date','items','subtotal','tax','total','flags']
ireq=['name','qty','unit_price','amount']
errors=[]; warnings=[]
if len(data)!=20: errors.append(f'객체 수 {len(data)}')
expected=[f'R{i:03}' for i in range(1,21)]
ids=[x.get('receipt_id') for x in data]
if ids!=expected: errors.append(f'ID 순서/집합 오류: {ids}')
for n,r in enumerate(data,1):
 miss=[k for k in required if k not in r]
 extra=[k for k in r if k not in required]
 if miss or extra: errors.append(f'R{n:03} 최상위 키 miss={miss} extra={extra}')
 if not isinstance(r.get('items'),list): errors.append(f'R{n:03} items 배열 아님'); continue
 if not isinstance(r.get('flags'),list) or not all(isinstance(x,str) for x in r.get('flags',[])): errors.append(f'R{n:03} flags 형식 오류')
 if not re.fullmatch(r'\d{4}-\d{2}-\d{2}',str(r.get('date'))): errors.append(f'R{n:03} 날짜 형식 오류')
 for j,it in enumerate(r['items'],1):
  miss=[k for k in ireq if k not in it]; extra=[k for k in it if k not in ireq]
  if miss or extra: errors.append(f'R{n:03} item{j} 키 오류 miss={miss} extra={extra}')
  for k in ['qty','unit_price','amount']:
   if it.get(k) is not None and (not isinstance(it[k],int) or isinstance(it[k],bool)): errors.append(f'R{n:03} item{j}.{k} 정수/null 아님')
  if all(it.get(k) is not None for k in ['qty','unit_price','amount']) and it['qty']*it['unit_price']!=it['amount']:
   warnings.append(f'R{n:03} item{j}: qty*unit_price != amount')
 for k in ['subtotal','tax','total']:
  if r.get(k) is not None and (not isinstance(r[k],int) or isinstance(r[k],bool)): errors.append(f'R{n:03} {k} 정수/null 아님')
 amounts=[it.get('amount') for it in r['items']]
 if all(v is not None for v in amounts) and sum(amounts)!=r.get('subtotal'):
  warnings.append(f"R{n:03}: 품목합 {sum(amounts):,} != subtotal {r.get('subtotal'):,}")
 if r.get('subtotal') is not None and r.get('tax') is not None and r.get('total') is not None and r['subtotal']+r['tax']!=r['total']:
  warnings.append(f"R{n:03}: subtotal+tax {r['subtotal']+r['tax']:,} != total {r['total']:,}")
print(json.dumps({'count':len(data),'ids_ok':ids==expected,'schema_errors':errors,'arithmetic_warnings':warnings,'flagged_ids':[r['receipt_id'] for r in data if r['flags']],'null_fields':[f"{r['receipt_id']} items[{j}].{k}" for r in data for j,it in enumerate(r['items']) for k in ireq if it.get(k) is None]},ensure_ascii=False,indent=2))
PY'''
